2272 void VPWidenRecipe::execute(VPTransformState &State) {
2273   auto &Builder = State.Builder;
2274   switch (Opcode) {
2275   case Instruction::Call:
2276   case Instruction::Br:
2277   case Instruction::PHI:
2278   case Instruction::GetElementPtr:
2279     llvm_unreachable("This instruction is handled by a different recipe.");
2280   case Instruction::UDiv:
2281   case Instruction::SDiv:
2282   case Instruction::SRem:
2283   case Instruction::URem:
2284   case Instruction::Add:
2285   case Instruction::FAdd:
2286   case Instruction::Sub:
2287   case Instruction::FSub:
2288   case Instruction::FNeg:
2289   case Instruction::Mul:
2290   case Instruction::FMul:
2291   case Instruction::FDiv:
2292   case Instruction::FRem:
2293   case Instruction::Shl:
2294   case Instruction::LShr:
2295   case Instruction::AShr:
2296   case Instruction::And:
2297   case Instruction::Or:
2298   case Instruction::Xor: {
2299     // Just widen unops and binops.
2300     SmallVector<Value *, 2> Ops;
2301     for (VPValue *VPOp : operands())
2302       Ops.push_back(State.get(VPOp));
2303 
2304     Value *V = Builder.CreateNAryOp(Opcode, Ops);
2305 
2306     if (auto *VecOp = dyn_cast<Instruction>(V)) {
2307       applyFlags(*VecOp);
2308       applyMetadata(*VecOp);
2309     }
2310 
2311     // Use this vector value for all users of the original instruction.
2312     State.set(this, V);
2313     break;
2314   }
2315   case Instruction::ExtractValue: {
2316     assert(getNumOperands() == 2 && "expected single level extractvalue");
2317     // Fetch the struct operand as a scalar so that extractvalue is valid
2318     // on the struct type, regardless of whether it is a widened struct of
2319     // vectors or a scalar struct constant folded by VPlan simplification.
2320     Value *Op = State.get(getOperand(0), /*NeedsScalar=*/true);
2321     Value *Extract = Builder.CreateExtractValue(
2322         Op, cast<VPConstantInt>(getOperand(1))->getZExtValue());
2323     if (!Extract->getType()->isVectorTy())
2324       Extract = Builder.CreateVectorSplat(State.VF, Extract);
2325     State.set(this, Extract);
2326     break;
2327   }
2328   case Instruction::Freeze: {
2329     Value *Op = State.get(getOperand(0));
2330     Value *Freeze = Builder.CreateFreeze(Op);
2331     State.set(this, Freeze);
2332     break;
2333   }
2334   case Instruction::ICmp:
2335   case Instruction::FCmp: {
2336     // Widen compares. Generate vector compares.
2337     bool FCmp = Opcode == Instruction::FCmp;
2338     Value *A = State.get(getOperand(0));
2339     Value *B = State.get(getOperand(1));
2340     Value *C = nullptr;
2341     if (FCmp) {
2342       C = Builder.CreateFCmp(getPredicate(), A, B);
2343     } else {
2344       C = Builder.CreateICmp(getPredicate(), A, B);
2345     }
2346     if (auto *I = dyn_cast<Instruction>(C)) {
2347       applyFlags(*I);
2348       applyMetadata(*I);
2349     }
2350     State.set(this, C);
2351     break;
2352   }
2353   case Instruction::Select: {
2354     VPValue *CondOp = getOperand(0);
2355     Value *Cond = State.get(CondOp, vputils::isSingleScalar(CondOp));
2356     Value *Op0 = State.get(getOperand(1));
2357     Value *Op1 = State.get(getOperand(2));
2358     Value *Sel = State.Builder.CreateSelect(Cond, Op0, Op1);
2359     State.set(this, Sel);
2360     if (auto *I = dyn_cast<Instruction>(Sel)) {
2361       if (isa<FPMathOperator>(I))
2362         applyFlags(*I);
2363       applyMetadata(*I);
2364     }
2365     break;
2366   }
2367   default:
2368     // This instruction is not vectorized by simple widening.
2369     LLVM_DEBUG(dbgs() << "LV: Found an unhandled opcode : "
2370                       << Instruction::getOpcodeName(Opcode));
2371     llvm_unreachable("Unhandled instruction!");
2372   } // end of switch.
2373 
2374 #if !defined(NDEBUG)
2375   // Verify that VPlan type inference results agree with the type of the
2376   // generated values.
2377   assert(VectorType::get(State.TypeAnalysis.inferScalarType(this), State.VF) ==
2378              State.get(this)->getType() &&
2379          "inferred type and type from generated instructions do not match");
