2487 bool VPWidenIntOrFpInductionRecipe::isCanonical() const {
2488   // The step may be defined by a recipe in the preheader (e.g. if it requires
2489   // SCEV expansion), but for the canonical induction the step is required to be
2490   // 1, which is represented as live-in.
